    void affine_transform(long long int input[INPUT_SIZE], long long int output[LAYER_SIZE]) {
        for (int i = 0; i < LAYER_SIZE; i++) {
            long long int acc = 0;
            for (int j = 0; j < INPUT_SIZE; j++) {
                // Product of two scaled numbers results in a number scaled by SCALE_FACTOR^2
                acc += weights[i][j] * input[j];
            }
            // Rescale accumulator (div by SCALE_FACTOR) and add scaled bias
            output[i] = (acc / SCALE_FACTOR) + biases[i];
        }
    }

    int check_preimage_inclusion(long long int output[LAYER_SIZE]) {
        for (int i = 0; i < LAYER_SIZE; i++) {
            // Apply ReLU before checking inclusion
            long long int relu_output = output[i] > 0 ? output[i] : 0;
            if (relu_output < preimage_low[i] || relu_output > preimage_high[i]) {
                return 0; // Violation found
            }
        }
        return 1; // All outputs within preimage
    }

    int main() {
        long long int input[INPUT_SIZE];
        long long int output[LAYER_SIZE];
        
        // Non-deterministic input within scaled integer bounds
        for (int i = 0; i < INPUT_SIZE; i++) {
            input[i] = nondet_longlong();
            __ESBMC_assume(input[i] >= input_low[i] && input[i] <= input_high[i]);
        }
        
        affine_transform(input, output);
        
        int inclusion_holds = check_preimage_inclusion(output);
        __ESBMC_assert(inclusion_holds, "Preimage inclusion violated for layer 0");
        
        return 0;
    }
    